88	static usb_sts_type class_init_handler(void *udev)
89	{
90	  usb_sts_type status = USB_OK;
91	  usbd_core_type *pudev = (usbd_core_type *)udev;
92	  cdc_struct_type *pcdc = (cdc_struct_type *)pudev->class_handler->pdata;
93	
94	#ifndef USB_EPT_AUTO_MALLOC_BUFFER
95	  /* use user define buffer address */
96	  usbd_ept_buf_custom_define(pudev, USBD_CDC_INT_EPT, EPT2_TX_ADDR);
97	  usbd_ept_buf_custom_define(pudev, USBD_CDC_BULK_IN_EPT, EPT1_TX_ADDR);
98	  usbd_ept_buf_custom_define(pudev, USBD_CDC_BULK_OUT_EPT, EPT1_RX_ADDR);
99	#endif
100	
101	  /* open in endpoint */
102	  usbd_ept_open(pudev, USBD_CDC_INT_EPT, EPT_INT_TYPE, USBD_CDC_CMD_MAXPACKET_SIZE);
103	
104	  /* open in endpoint */
105	  usbd_ept_open(pudev, USBD_CDC_BULK_IN_EPT, EPT_BULK_TYPE, USBD_CDC_IN_MAXPACKET_SIZE);
106	
107	  /* open out endpoint */
108	  usbd_ept_open(pudev, USBD_CDC_BULK_OUT_EPT, EPT_BULK_TYPE, USBD_CDC_OUT_MAXPACKET_SIZE);
109	
110	  /* set out endpoint to receive status */
111	  usbd_ept_recv(pudev, USBD_CDC_BULK_OUT_EPT, pcdc->g_rx_buff, USBD_CDC_OUT_MAXPACKET_SIZE);
112	
113	  cdc_struct_init(pcdc);
114	
115	  return status;
116	}
