140	/**
141	  * @brief  usb device class setup request handler
142	  * @param  udev: to the structure of usbd_core_type
143	  * @param  setup: setup packet
144	  * @retval status of usb_sts_type
145	  */
146	static usb_sts_type class_setup_handler(void *udev, usb_setup_type *setup)
147	{
148	  usb_sts_type status = USB_OK;
149	  usbd_core_type *pudev = (usbd_core_type *)udev;
150	  cdc_struct_type *pcdc = (cdc_struct_type *)pudev->class_handler->pdata;
151	
152	  switch(setup->bmRequestType & USB_REQ_TYPE_RESERVED)
153	  {
154	    /* class request */
155	    case USB_REQ_TYPE_CLASS:
156	      if(setup->wLength)
157	      {
158	        if(setup->bmRequestType & USB_REQ_DIR_DTH)
159	        {
160	          usb_vcp_cmd_process(udev, setup->bRequest, pcdc->g_cmd, setup->wLength);
161	          usbd_ctrl_send(pudev, pcdc->g_cmd, setup->wLength);
162	        }
163	        else
164	        {
165	          pcdc->g_req = setup->bRequest;
166	          pcdc->g_len = setup->wLength;
167	          usbd_ctrl_recv(pudev, pcdc->g_cmd, pcdc->g_len);
168	
169	        }
170	      }
171	      break;
172	    /* standard request */
173	    case USB_REQ_TYPE_STANDARD:
174	      switch(setup->bRequest)
175	      {
176	        case USB_STD_REQ_GET_DESCRIPTOR:
177	          usbd_ctrl_unsupport(pudev);
178	          break;
179	        case USB_STD_REQ_GET_INTERFACE:
180	          usbd_ctrl_send(pudev, (uint8_t *)&pcdc->alt_setting, 1);
181	          break;
182	        case USB_STD_REQ_SET_INTERFACE:
183	          pcdc->alt_setting = setup->wValue;
184	          break;
185	        default:
186	          break;
187	      }
188	      break;
189	    default:
190	      usbd_ctrl_unsupport(pudev);
191	      break;
192	  }
193	  return status;
194	}
