321	  */
322	static usb_sts_type cdc_struct_init(cdc_struct_type *pcdc)
323	{
324	  pcdc->g_tx_completed = 1;
325	  pcdc->g_rx_completed = 0;
326	  pcdc->alt_setting = 0;
327	  pcdc->linecoding.bitrate = linecoding.bitrate;
328	  pcdc->linecoding.data = linecoding.data;
