334	/**
335	  * @brief  usb device class rx data process
336	  * @param  udev: to the structure of usbd_core_type
337	  * @param  recv_data: receive buffer
338	  * @retval receive data len
339	  */
340	uint16_t usb_vcp_get_rxdata(void *udev, uint8_t *recv_data)
341	{
342	  uint16_t i_index = 0;
343	  uint16_t tmp_len = 0;
344	  usbd_core_type *pudev = (usbd_core_type *)udev;
345	  cdc_struct_type *pcdc = (cdc_struct_type *)pudev->class_handler->pdata;
346	
347	  if(pcdc->g_rx_completed == 0)
348	  {
349	    return 0;
350	  }
351	  pcdc->g_rx_completed = 0;
352	  tmp_len = pcdc->g_rxlen;
353	  for(i_index = 0; i_index < pcdc->g_rxlen; i_index ++)
354	  {
355	    recv_data[i_index] = pcdc->g_rx_buff[i_index];
356	  }
357	
358	  usbd_ept_recv(pudev, USBD_CDC_BULK_OUT_EPT, pcdc->g_rx_buff, USBD_CDC_OUT_MAXPACKET_SIZE);
359	
360	  return tmp_len;
361	}
362	
363	/**
364	  * @brief  usb device class send data
365	  * @param  udev: to the structure of usbd_core_type
366	  * @param  send_data: send data buffer
367	  * @param  len: send length
368	  * @retval error status
369	  */
370	error_status usb_vcp_send_data(void *udev, uint8_t *send_data, uint16_t len)
371	{
372	  error_status status = SUCCESS;
373	  usbd_core_type *pudev = (usbd_core_type *)udev;
374	  cdc_struct_type *pcdc = (cdc_struct_type *)pudev->class_handler->pdata;
375	  if(pcdc->g_tx_completed)
376	  {
377	    pcdc->g_tx_completed = 0;
378	    usbd_ept_send(pudev, USBD_CDC_BULK_IN_EPT, send_data, len);
379	  }
380	  else
381	  {
382	    status = ERROR;
383	  }
384	  return status;
385	}
386	
387	
388	/**
389	  * @brief  usb device class request function
390	  * @param  udev: to the structure of usbd_core_type
391	  * @param  cmd: request number
392	  * @param  buff: request buffer
393	  * @param  len: buffer length
394	  * @retval none
395	  */
396	static void usb_vcp_cmd_process(void *udev, uint8_t cmd, uint8_t *buff, uint16_t len)
397	{
398	  usbd_core_type *pudev = (usbd_core_type *)udev;
399	  cdc_struct_type *pcdc = (cdc_struct_type *)pudev->class_handler->pdata;
400	  switch(cmd)
401	  {
402	    case SET_LINE_CODING:
403	      pcdc->linecoding.bitrate = (uint32_t)(buff[0] | (buff[1] << 8) | (buff[2] << 16) | (buff[3] <<24));
404	      pcdc->linecoding.format = buff[4];
405	      pcdc->linecoding.parity = buff[5];
406	      pcdc->linecoding.data = buff[6];
407	#ifdef USB_VIRTUAL_COMPORT
408	      /* set hardware usart */
409	      usb_usart_config(pcdc->linecoding);
410	#endif
411	      break;
412	
413	    case GET_LINE_CODING:
414	      buff[0] = (uint8_t)pcdc->linecoding.bitrate;
415	      buff[1] = (uint8_t)(pcdc->linecoding.bitrate >> 8);
416	      buff[2] = (uint8_t)(pcdc->linecoding.bitrate >> 16);
417	      buff[3] = (uint8_t)(pcdc->linecoding.bitrate >> 24);
418	      buff[4] = (uint8_t)(pcdc->linecoding.format);
419	      buff[5] = (uint8_t)(pcdc->linecoding.parity);
420	      buff[6] = (uint8_t)(pcdc->linecoding.data);
421	      break;
422	
423	    default:
424	      break;
425	  }
426	}
