45	        if (data_len > 0) {
46	            /* 存储到帧缓冲区 */
47	            if ((usb_rx_index + data_len) <= E32K_SIZE) {
48	                for (uint8_t i = 0; i < data_len; i++) {
49	                    usb_rx_frame[usb_rx_index + i] = UsbRxBuf[i];
50	                }
51	                usb_rx_index += data_len;
52	                FrameFlag = 0;
53	                // LOG("Received %u bytes from USB", data_len);
54	                memset(UsbRxBuf, 0, sizeof(UsbRxBuf));
55	            } else {
56	                LOGE("USB buffer overflow");
57	                usb_rx_index = 0;
58	            }
59	        } else {
60	            /* 检查是否接收到完整帧 */
61	            if (FrameFlag == 0 && usb_rx_index >= 2) {
62	                uint8_t device = usb_rx_frame[0];
63	                function_code  = usb_rx_frame[1];
64	
65	                LOGI("USB_TASK, Device:%d, Function:0x%02X, Len:%u", device, function_code, usb_rx_index);
66	                /* 调试打印 */
67	                for (uint16_t i = 0; i < usb_rx_index && i < 10; i++) {
68	                    LOG(" %02X", usb_rx_frame[i]);
69	                }
70	                // LOG("Write length: %u bytes", ((uint16_t)usb_rx_frame[8] << 8) | usb_rx_frame[9]);
71	                /* 解析命令 */
72	                cmd.type     = 0;
73	                cmd.device   = device;
74	                cmd.reg_addr = 0;
75	                cmd.data_len = 0;
76	                cmd.data     = usb_rx_frame;
77	                cmd.resp_len = usb_rx_index;
78	
79	                /* 根据功能码设置命令类型 */
80	                switch (function_code) {
81	                    case 0x22:
82	                        cmd.type = 1;
83	                        for (uint16_t i = 0; i < usb_rx_index; i++) {
84	                            cmd.response[i] = usb_rx_frame[i];
85	                        }
86	                        break; /* 看门狗 */
87	                    case 0x04:
88	                        cmd.type = 2;
89	                        GetCrC(usb_rx_frame, 4, crc);
90	                        for (uint16_t i = 0; i < usb_rx_index; i++) {
91	                            cmd.response[i] = usb_rx_frame[i];
92	                        }
93	                        break; /* 重置 */
94	                    case 0x03: /* 读寄存器 */
95	                        cmd.type     = 3;
96	                        cmd.reg_addr = (usb_rx_frame[4] << 8) | usb_rx_frame[5];
97	                        cmd.data_len = (usb_rx_frame[8] << 8) | usb_rx_frame[9];
98	                        GetCrC(usb_rx_frame, 10, crc);
99	                        if (cmd.device == 0) {
100	                            cmd.type = 0; /* 特例：用于访问左右耳连接状态。 */
101	                            if ((crc[0] == usb_rx_frame[10]) && (crc[1] == usb_rx_frame[11])) {
102	                                if (0 == usb_rx_frame[0]) {
103	                                    uint8_t stutas1 = 0;
104	                                    stutas1 |= ConnI2c1_flag;
105	                                    stutas1 |= (ConnI2c2_flag << 1);
106	                                    switch (stutas1) {
107	                                        case 0:
108	                                            connectstatus[6] = 0x00;
109	                                            connectstatus[7] = 0x1A;
110	                                            connectstatus[8] = 0xA3;
111	                                            break;
112	                                        case 1:
113	                                            connectstatus[6] = 0x01;
114	                                            connectstatus[7] = 0xDB;
115	                                            connectstatus[8] = 0x63;
116	                                            break;
117	                                        case 2:
118	                                            connectstatus[6] = 0x02;
119	                                            connectstatus[7] = 0x9B;
120	                                            connectstatus[8] = 0x62;
121	                                            break;
122	                                        case 3:
123	                                            connectstatus[6] = 0x03;
124	                                            connectstatus[7] = 0x5A;
125	                                            connectstatus[8] = 0xA2;
126	                                            break;
127	                                        default:
128	                                            break;
129	                                    }
130	                                    usb_send_response_data(connectstatus, 9);
131	                                }
132	                            }
133	                        } else {
134	                            if (!((crc[0] == usb_rx_frame[10]) && (crc[1] == usb_rx_frame[11]))) {
135	                                LOGE("CRC check failed for device %d", cmd.device);
136	                                cmd.type = 0; // CRC校验失败，不发送命令
137	                            } else {
138	                                for (uint16_t i = 0; i < usb_rx_index; i++) {
139	                                    cmd.response[i] = usb_rx_frame[i];
140	                                }
141	                            }
142	                        }
143	                        break;
144	                    case 0x06: /* 写单个寄存器 */
145	                        cmd.type     = 4;
146	                        cmd.reg_addr = ((uint16_t)(usb_rx_frame[4]) << 8) | usb_rx_frame[5];
147	                        cmd.data_len = 1;
148	                        for (uint16_t i = 0; i < usb_rx_index; i++) {
149	                            cmd.response[i] = usb_rx_frame[i];
150	                        }
151	                        break;
152	                    case 0x10: /* 写多个寄存器 */
153	                        cmd.type     = 5;
154	                        cmd.reg_addr = ((uint16_t)(usb_rx_frame[4]) << 8) | usb_rx_frame[5];
155	                        cmd.data_len = ((uint16_t)(usb_rx_frame[8]) << 8) | usb_rx_frame[9];
156	                        if (usb_rx_index < (cmd.data_len + 5)) {
157	                            LOGW("0x10 command incomplete: %u/%u bytes, waiting...",
158	                                 usb_rx_index, cmd.data_len);
159	                            continue; // 继续等待
160	                        }
161	                        GetCrC(usb_rx_frame, cmd.data_len + 10, crc);
162	
163	                        uint32_t end_addr = cmd.reg_addr + cmd.data_len - 1;
164	
165	                        if ((cmd.reg_addr <= SN_ADDR + SN_SIZE - 1) && (end_addr >= SN_ADDR)) {
166	                            LOGW("Warning: Write operation may overwrite SN area!");
167	                            LOGW("SN area: 0x%04X-0x%04X", SN_ADDR, SN_ADDR + SN_SIZE - 1);
168	                            LOGW("This write: 0x%04X-0x%04X", cmd.reg_addr, end_addr);
169	                            // cmd.type = 0; /* 特例：禁止写入SN区域 */
170	                        }
171	                        break;
172	                    default:
173	                        LOGW("Unknown function code: 0x%02X", function_code);
174	                        break;
175	                }
176	
177	                /* 发送命令到I2C任务 */
178	                if (cmd.type != 0) {
179	                    cmd.completion_sem = xSemaphoreCreateBinary();
180	                    if (cmd.completion_sem != NULL) {
181	                        if (xQueueSend(xCommandQueue, &cmd, portMAX_DELAY) == pdPASS) {
182	                            /* 等待I2C任务完成 */
183	                            if (xSemaphoreTake(cmd.completion_sem, pdMS_TO_TICKS(25000) ) == pdTRUE) {
184	
185	                                Response_t resp;
186	                                if (xQueueReceive(xResponseQueue, &resp, pdMS_TO_TICKS(5000)) == pdPASS) {
187	                                    if (resp.resp_len > 0) {
188	                                        // memcpy(cmd.response, resp.response, resp.resp_len);
189	                                        // cmd.resp_len = resp.resp_len;
190	                                        LOGI("Command processed - Type:%d, Device:%d, RegAddr:0x%04X, DataLen:%u, RespLen:%u",
191	                                             cmd.type, cmd.device, cmd.reg_addr, cmd.data_len, cmd.resp_len);
192	                                        /* 发送响应 */
193	                                        usb_send_response(resp.resp_len);
194	                                    } else {
195	                                        LOGI("Failed to get response in time");
196	                                    }
197	                                }
198	                            } else {
199	                                LOGE("Command 0x%02X timeout", function_code);
200	                            }
201	                        }
202	                        vSemaphoreDelete(cmd.completion_sem);
203	                    }
204	                }
205	                memset(usb_rx_frame, 0, sizeof(usb_rx_frame)); // 清空帧缓冲区
206	                memset(UsbRxBuf, 0, sizeof(UsbRxBuf));         // 清空USB接收缓冲区
207	                memset(&cmd, 0, sizeof(Command_t));
208	                /* 清空缓冲区 */
209	                usb_rx_index = 0;
210	                FrameFlag    = 1;
211	                FrameFinish  = 1;
212	            }
213	        }
214	
215	        vTaskDelayUntil(&xLastWakeTime, xFrequency);
216	    }
217	}
